const { WorkOS } = require('@workos-inc/node');
const fs = require('fs');
const path = require('path');

async function main() {
  try {
    const apiKey = process.env.WORKOS_API_KEY;
    if (!apiKey) {
      console.error('WORKOS_API_KEY environment variable is missing.');
      process.exit(1);
    }

    const workos = new WorkOS(apiKey);

    const organization = await workos.organizations.createOrganization({
      name: 'Acme Corp',
      domainData: [
        {
          domain: 'acmecorp.com',
          state: 'pending'
        }
      ]
    });

    const orgIdPath = '/home/user/org_id.txt';
    fs.writeFileSync(orgIdPath, organization.id);
    console.log(`Successfully created organization: ${organization.id}`);

    // Copy artifacts
    const artifactsDir = '/logs/artifacts/code';
    if (!fs.existsSync(artifactsDir)) {
      fs.mkdirSync(artifactsDir, { recursive: true });
    }
    fs.copyFileSync(__filename, path.join(artifactsDir, 'create_org.js'));
    fs.copyFileSync(orgIdPath, path.join(artifactsDir, 'org_id.txt'));

  } catch (error) {
    console.error('Error creating organization:', error.response?.data || error.message || error);
    process.exit(1);
  }
}

main();

